(window.WISE_WORLD_Q = window.WISE_WORLD_Q || {}).sw = [
  { id:1, topic:"Sayansi ya kunawa", emoji:"🧼",
    question:"Mikononi mwako mkiwa na vijidudu au virusi vinavyoleta magonjwa, kwa nini kunawa kwa 'sabuni' ni salama zaidi sana kuliko kunawa kwa maji tu?",
    choices:["Umbo la povu la sabuni huviogopesha vijidudu na kuvifukuza mbali","Sabuni inaweza kuvunja kabisa utando wa mafuta (ganda la nje) unaomzunguka virusi na kuuyeyusha","Sabuni hufanya ngozi ya mikono yako migumu kama chuma hivyo huzuia vijidudu","Harufu ya sabuni huzuia vijidudu kupumua"],
    answerIndex:1,
    explanation:"Uso wa vijidudu na virusi vingi (kama vya homa ya mafua) kwa kweli umelindwa na utando mwembamba wa mafuta uitwao 'lipidi'. Utando huu ndio unaowapa nguvu ya kuvamia mwili wa binadamu. Mafuta hayaondoki kamwe kwa maji peke yake, lakini molekuli za sabuni zina uwezo wa kuyazunguka mafuta na kuyayeyusha majini. Unaposugua mikono kwa sabuni, utando wa mafuta unaolinda virusi huyeyuka vipande vipande papo hapo, virusi havibaki hai tena na huharibiwa kabisa. Kunawa kwa sabuni si kuondoa tu vijidudu mikononi, bali ni 'dawa' yenye nguvu zaidi inayoangamiza adui kisayansi." },
  { id:2, topic:"Kushinikiza moja kwa moja", emoji:"🩹",
    question:"Unapoumia jeraha refu na damu inabubujika, ni 'huduma sahihi ya kwanza (kushinikiza moja kwa moja)' gani ya kufanya kwanza kabisa ili kuokoa uhai?",
    choices:["Kupapasa jeraha mfululizo kwa kitambaa kilicholowekwa maji","Kuweka kitambaa safi moja kwa moja juu ya jeraha na kushinikiza kwa nguvu kutoka juu kwa uzito wa mwili","Kutikisa jeraha kwa nguvu hadi damu isimame","Kufunika jeraha kwa udongo ili kuzuia damu"],
    answerIndex:1,
    explanation:"Kupoteza damu nyingi ni hatari kubwa kuliko zote: oksijeni hukoma kufika kwenye chembe na unaweza kupoteza uhai papo hapo. Msingi wa kitabibu duniani kote unaozuia hilo ni 'kushinikiza moja kwa moja'. Kwa kushinikiza kwa nguvu mshipa uliopasuka kutoka nje, unaziba kimwili njia ya damu kupita. Zaidi, kushinikiza husaidia 'chembe sahani' za damu, timu inayotengeneza kigaga, kukusanyika jeraheni na kuziba tundu. Kupangusa kwa upole nusunusu hakusimamishi damu. Hekima ya kushinikiza kwa nguvu kwa mikono miwili huushika uhai wa mtu." },
  { id:3, topic:"Kuweka banzi kwa mvunjiko", emoji:"🦴",
    question:"Unaposhuku 'mfupa wa mguu au mkono umevunjika (mvunjiko)' baada ya kuanguka, kwa nini usilazimishe kamwe sehemu hiyo kusogea?",
    choices:["Kuusogeza hugeuza mfupa ghafla kuwa mpira mviringo","Ncha kali ya mfupa uliovunjika inaweza kurarua misuli, mishipa na neva muhimu chini ya ngozi, ikasababisha kutokwa damu kwingi au kupooza","Kuusogeza mfupa huufanya uwe mzito mara kumi","Mfupa huogopa na kutoweka mwilini"],
    answerIndex:1,
    explanation:"Mfupa unapovunjika chini ya ngozi, ncha yake iliyovunjika ni kali sana na yenye ncha, kama kipande cha kioo. Ukilazimisha sehemu hiyo kusogea ukijiuliza 'je, naweza kutembea?', kisu hicho cha mfupa husogea ndani ya nguo na misuli, hukata mshipa mnene ulio karibu na kusababisha kutokwa damu ndani, au huumiza neva na kuleta kupooza kusiko pona kamwe. Unaposhuku mvunjiko, weka tawi au ubao mgumu (banzi) na ufunge kwa pamoja kiungo cha juu na cha chini ya mahali pa kuvunjika, ili kisisogee hata milimita moja huku ukisubiri matibabu. Hiyo ndiyo hekima sahihi ya dharura." },
  { id:4, topic:"Kutibu kuungua", emoji:"🔥",
    question:"Unapogusa moto au maji ya moto ukaungua, ni jambo gani la kwanza kabisa la kufanya, kwa haraka sana, kabla ya yote?",
    choices:["Kupaka mafuta au udongo jeraheni ili lisikauke","Kupooza jeraha kwa maji baridi safi, kulishikilia angalau dakika 15, hadi maumivu yapungue","Kung'oa ngozi iliyoungua kwa kucha vizuri","Kulifunika kwa kitambaa cha joto ili kuhifadhi joto"],
    answerIndex:1,
    explanation:"Jambo la kutisha kuhusu kuungua ni kwamba, hata baada ya kuondoa mkono kutoka kitu cha moto, nishati kubwa ya joto iliyobaki juu ya ngozi huendelea kupenya kwa kina (kwenye safu ya ngozi ya ndani na misuli) kama kaa la moto, ikiharibu chembe. Njia pekee ya kulizuia ni kuiba joto hilo haraka iwezekanavyo kwa maji baridi. Kupooza zaidi ya dakika 15 husimamisha wimbi la joto liendalo ndani na kufanya jeraha lisiwe la kina kadiri inavyowezekana. Iwapo kupooza kwa awali hakutoshi, ngozi hufa kwa kina, huacha kovu kubwa maisha yote na hurahisisha vijidudu kuingia. Kupooza kwa maji ni 'breki' ya kisayansi dhidi ya kuenea kwa kuungua." },
  { id:5, topic:"Maji ya kurudisha maji mwilini", emoji:"🥤",
    question:"Kuhara au kutapika kukali kunapoukausha mwili, kwa nini ni bora kisayansi kunywa maji yaliyochanganywa na 'chumvi' kidogo na 'sukari' (maji ya kurudisha maji mwilini) kuliko maji ya kawaida?",
    choices:["Kuchanganya chumvi na sukari hufanya maji yawe matamu na moyo ufurahi","Ukuta wa utumbo mwembamba una mlango maalumu unaonyonya maji kwa kasi kubwa wakati kiini cha chumvi (sodiamu) na cha sukari (glukosi) vinapofika pamoja","Chumvi huchoma na kuua moja kwa moja vijidudu vya kuhara","Kunywa sukari hugandisha tumbo papo hapo na kusimamisha kuhara"],
    answerIndex:1,
    explanation:"Wakati wa kuhara au kutapika kukali, ukuta wa utumbo umejeruhiwa, hivyo hata maji ya kawaida hayanyonywi vizuri na hutoka upande mwingine. Lakini ukuta wa utumbo mwembamba wa binadamu una mlango (SGLT-1): sodiamu na glukosi vinapofika pamoja kwa uwiano wa 1 kwa 2, hunyonya maji ndani ya chembe papo hapo kama pampu yenye nguvu. Kinachotumia hili ni 'maji ya kurudisha maji mwilini', yaliyookoa maisha mengi duniani kote. Maji haya ya kimuujiza, yaliyotengenezwa kwa kuchanganya nusu kijiko cha chai cha chumvi na vijiko vinne na nusu vikubwa vya sukari katika lita moja ya maji, yanaweza kuokoa uhai kutokana na ukosefu wa maji hata pasipo dripu ya mshipani. Hii ndiyo hekima ya tiba." },
  { id:6, topic:"Kumbukumbu ya kinga", emoji:"💉",
    question:"Mtu akishapata ugonjwa fulani mkali, kama surua, ni nadra kupata ugonjwa ule ule tena. Mfumo huu wa ajabu ndani ya mwili huitwaje?",
    choices:["Kuhuisha mifupa","Mfumo wa kumbukumbu wa kinga","Kuwa fuwele kwa damu","Udanganyifu wa ubongo"],
    answerIndex:1,
    explanation:"Ndani ya miili yetu, timu ya kinga, ikiwemo 'chembe nyeupe za damu' zinazopigana na vijidudu na virusi, hudoria saa 24. Virusi vikali vinapovamia kwa mara ya kwanza, huchukua siku nyingi kutengeneza silaha (kingamwili) ya kupigana navyo, na katika muda huo unaweza kuugua sana. Lakini la ajabu kuhusu timu ya kinga ni kwamba huhifadhi kabisa 'umbo na alama' za adui iliyepigana naye mara moja, na kuziweka ubongoni na chembeni. Miaka baadaye, adui yule yule akivamia tena, hutumia kumbukumbu hiyo kutengeneza kiasi kikubwa cha silaha sahihi papo hapo na kumwangamiza kwa pigo moja kabla hujaugua. Teknolojia inayotumia hili, kupanda kumbukumbu tu kwa usalama kabla ya kuugua, ni 'chanjo'." },
  { id:7, topic:"Mnyama akikuuma", emoji:"🐕",
    question:"Mbwa-mwitu, mbweha, popo au mnyama mwingine akikuuma, hata jeraha likionekana dogo, kwa nini lazima ukimbilie kuliosha kwa maji mengi na sabuni, jambo la uhai au kifo?",
    choices:["Rangi ya meno ya mnyama inaweza kuhamia ngozini mwako","Mate ya mnyama yanaweza kuficha virusi vya kutisha kama vya kichaa cha mbwa, vinavyoharibu ubongo na kuua karibu 100% ya wanaoambukizwa","Usipoosha, manyoya mapya yatamea mahali pa kuumwa","Ili kumwonyesha mnyama shukrani yako"],
    answerIndex:1,
    explanation:"Duniani kote kuna ugonjwa wa kutisha uitwao 'kichaa cha mbwa', unaoenea kwa binadamu mnyama mwenye virusi anapomuuma. Virusi hivi vikiingia mwilini na kusafiri kupitia neva hadi ubongoni, basi dalili zikishaonekana, hata tiba ya kisasa karibu kamwe haimwokoi mtu, naye hufa. Hata hivyo, kuna nafasi fupi ya muda kabla virusi haijaingia kwenye neva kutoka jeraheni. Mara baada ya kuumwa, kuosha jeraha kwa nguvu chini ya maji mengi yanayotiririka safi na sabuni zaidi ya dakika 15 huosha kimwili na kupunguza virusi vilivyoshikamana na jeraha na kunaweza kuzuia kufika ubongoni. Mnyama akikuuma, 'osha kwa nguvu kabla ya yote': hii ndiyo kanuni kamili ya tiba inayoamua uhai au kifo." },
  { id:8, topic:"Viumbe wenye sumu", emoji:"🐍",
    question:"Nyoka mwenye sumu, buibui au kiumbe mwingine hatari akikuuma mkono au mguu, ni 'kitendo kibaya' gani usichopaswa kufanya kamwe?",
    choices:["Kutosogeza mahali pa kuumwa na kulala kimya","Kushtuka, kupiga kelele kwa sauti kubwa na kukimbia huku na huko kutoroka","Kumwambia mtu mzima aliye karibu ni kiumbe gani hasa kilichokuuma","Kuweka jeraha chini ya moyo"],
    answerIndex:1,
    explanation:"Kiumbe mwenye sumu akikuuma, ukishtuka kwa woga ukakimbia huku na huku au ukapiga zogo kubwa, mapigo ya moyo wako (mpigo) huongezeka ghafla. Ndipo sumu iliyoingia jeraheni hupanda damu inayokimbia kwa kasi na kusambaa papo hapo kwenye misuli, ubongo na viungo vya ndani vya mwili mzima, hivyo sumu husambaa kwa kasi zaidi sana na unaweza kupoteza uhai. Kitu chenye sumu kikikuuma, sahihi ni kutuliza moyo, usikimbie, usisogee, na ulale kimya bila kusogea. Kwa kuweka jeraha chini kidogo ya moyo, unapunguza kasi ya damu yenye sumu kurudi moyoni. Kubaki mtulivu na bila kusogea ndio ngao yenyewe inayozuia kuenea kwa sumu." },
  { id:9, topic:"Jasho na chumvi", emoji:"💦",
    question:"Siku ya joto baada ya kutoka 'jasho' jingi, hata ukiwa na kiu, kwa nini kunywa kwa pamoja kiasi kikubwa cha 'maji safi yasiyo na chumvi' tu kunakufanya kwa kweli ujisikie vibaya zaidi?",
    choices:["Kunywa maji safi hufanya maji ya tumboni yaoze","Kwa kuwa chumvi (sodiamu) pia hupotea mwilini pamoja na jasho, kunywa maji tu hupunguza kiwango cha chumvi katika damu kupita kiasi, na ubongo na misuli haviwezi kufanya kazi vizuri (sodiamu chini)","Maji mengi huyeyusha mifupa yote ya mwili","Maji safi hubadilisha damu yako kutoka nyekundu kuwa bluu"],
    answerIndex:1,
    explanation:"Maji ya mwili (kama damu) huwa na takriban asilimia 0.9 ya 'chumvi' daima, na kwa sababu ya kiwango hiki sahihi, amri za neva hufika kwa usahihi kwenye misuli na ubongo. Unapotoka jasho jingi, chumvi hii muhimu huvuja nje pamoja na maji. Kisha ukimimina katika mwili huo tupu maji safi yasiyo na chumvi tu, kiwango cha chumvi ndani hupungua zaidi. Ndipo ubongo huhukumu 'kikipungua zaidi ni hatari!' na hukataa maji, au hujaribu kuyatoa nje kama jasho au mkojo. Matokeo yake, miguu hupata mkakamao mkali (mikakamao ya joto), na huja maumivu ya kichwa na kizunguzungu. Unapojaza maji siku ya joto, lazima daima uchukue chumvi kidogo sana kwa wakati mmoja." },
  { id:10, topic:"Kufungua njia ya hewa", emoji:"😮",
    question:"Mtu anapoanguka bila fahamu na pengine hapumui, ni nini lengo halisi la kumweka katika hali ya 'kuinua kidevu juu na kuegesha kichwa nyuma (kufungua njia ya hewa)'?",
    choices:["Kuelekeza uso juu ili mwanga wa jua uingie machoni","Unapopoteza fahamu, msuli mkubwa wa ndani ya koo (shina la ulimi) hulegea na kuanguka chini na kuziba kabisa njia ya hewa; hili huzuia kukabwa pumzi","Kunyoosha mifupa ya shingo ili mtu awe mrefu","Kumsaidia mtu aliyeanguka alale vizuri"],
    answerIndex:1,
    explanation:"Mtu anapopoteza fahamu na kulegea kabisa, msuli wa 'ulimi' wa ndani ya koo nao huzama nyuma kwa kulegea. Hili huitwa 'ulimi kuanguka nyuma'. Koo la mtu aliyelala chali huzibwa kabisa, njia ya hewa huzuiwa na ulimi wake mwenyewe, hivyo hawezi kupumua na hukabwa pumzi. Ili kuzuia hili, huku ukibonyeza paji la uso, tumia mkono mwingine kuinua mfupa wa kidevu kwa nguvu kuelekea angani. Hili hufungua kimwili nafasi ya ndani ya koo iwe pana, na hewa hufika mapafuni kwa urahisi. 'Kufungua njia ya hewa' huku ni hatua ya kwanza ya kuokoa uhai duniani kote, kabla ya kupuliza pumzi au kukandamiza kifua." },
  { id:11, topic:"Jinsi kupumua kunavyofanya kazi", emoji:"💨",
    question:"Tunapovuta na kutoa pumzi, kwa nini mwili wetu lazima utupe nje gesi iitwayo 'kaboni dioksidi'?",
    choices:["Kaboni dioksidi ikijaa mwilini, ngozi hugeuka kijani","Kaboni dioksidi ni taka yenye sumu inayozalishwa wakati chembe zinapochoma virutubisho ili kufanya kazi kwa nguvu, na ikijaa damuni, damu hugeuka tindikali na kuhatarisha uhai","Usipotoa kaboni dioksidi, mwili huvimba kama puto na kuelea angani","Ili kuweka ndani ya mwili baridi"],
    answerIndex:1,
    explanation:"Kama gari linavyochoma petroli na kutoa moshi, ndivyo trilioni za chembe za binadamu zinavyochoma virutubisho vya chakula kwa oksijeni ili kutengeneza nishati ya kuishi, na daima hutengeneza taka ya moshi iitwayo 'kaboni dioksidi'. Gesi hii ikiyeyuka kwa wingi damuni, ina nguvu ya sumu ya kuibadilisha damu kwa kasi kutoka isiyo na tindikali kuwa 'tindikali' hatari. Damu ikiwa tindikali, chembe za ubongo na moyo haziwezi tena kufanya kazi, na mtu hufa. Ndiyo maana haswa moyo huharakisha damu kwenda mapafuni, hutupa kaboni dioksidi sekunde moja mapema kwa kupumua na huchukua oksijeni mpya badala yake, mara kwa mara." },
  { id:12, topic:"Kazi ya moyo", emoji:"❤️",
    question:"Ni nini lengo halisi la 'moyo' upande wa kushoto wa kifua kupiga bila kupumzika, hata sekunde moja, tangu kuzaliwa hadi kufa?",
    choices:["Kusaga na kuvunja chakula tumboni","Kuzungusha 'lori la kupeleka la mwili' linalobeba damu iliyojaa oksijeni na virutubisho kwenda chembe za mwili mzima na kukusanya taka (kama kaboni dioksidi) zinazotolewa na chembe","Kusukuma nje maji ya ziada yaliyojaa mwilini","Kurudisha mwangwi wa sauti yake kuwaambia wenzako ulipo"],
    answerIndex:1,
    explanation:"Moyo ni pampu ya misuli yenye nguvu sana inayosukuma 'damu' inayotiririka mwilini mwetu. Damu hubeba oksijeni iliyopokelewa mapafuni na virutubisho vilivyonyonywa utumboni, na huvipeleka kwa chembe kutoka utosini hadi vidole vya miguu, ikitimiza jukumu la mpelekaji muhimu. Moyo ukisimama ghafla, mtiririko wa damu husimama kabisa. Ndipo chembe za ubongo, zinazohitaji oksijeni nyingi hasa, hupungukiwa nayo ndani ya dakika chache tu na kupata uharibifu wa kuangamiza usio pona kamwe, na hufa. Moyo kuendelea kupiga ni mfumo muhimu zaidi wa kudumisha uhai, unaopeleka 'posho ya kuishi' kwa chembe za mwili mzima." },
  { id:13, topic:"Kuokoa anayezama", emoji:"🆘",
    question:"Unamwona rafiki au mtu akizama mtoni au baharini. Ili kujilinda huku ukimsaidia, ni 'jambo gani usilopaswa kufanya kamwe'?",
    choices:["Kupiga kelele kwa sauti kubwa kwa watu wazima walio karibu, 'Aje mtu! Mtu anazama!' na kuita msaada","Kufikiri unaweza kuogelea na kumwokoa, na kuruka moja kwa moja majini mikono mitupu kumkamata anayezama","Kutupa kamba, fimbo ndefu au chupa ya plastiki tupu (badala ya kiokozi) juu ya maji","Kunyoosha mkono kutoka ardhi imara iliyo karibu"],
    answerIndex:1,
    explanation:"Mtu anayezama na asiyeweza kupumua yumo katika hofu kamili kwa woga wa kufa. Mtu akiogelea kumsaidia, anayezama, kwa nguvu kali isiyoaminika, hukushikilia kutoka juu ya kichwa ili kukutumia kama 'kiokozi' na kukusukuma chini ya maji. Hili likitokea, hata mtu mzima muogeleaji hodari huzama nawe hadi chini, na ajali ya kusikitisha ya watu wawili kuzama hutokea duniani kote bila kikomo. Mtu akizama, ni marufuku kabisa kuingia majini wewe mwenyewe. Piga kelele kwa nguvu kutoka mahali salama nchi kavu na utupe chochote 'kinachoelea', chupa tupu, kipande cha mti, ili akamate. Hii ndiyo kanuni sahihi ya kunusurika." },
  { id:14, topic:"Kuzuia pepopunda", emoji:"🔩",
    question:"Unapokanyaga msumari mkuukuu wenye kutu, au kuumia jeraha refu kwa kifaa cha zamani chenye udongo, kwa nini usipuuze hata baada ya siku, jeraha likishapona?",
    choices:["Chuma chenye kutu hugeuka sumaku ndani ya ngozi yako","Kijidudu kiitwacho bakteria wa pepopunda hupenda mahali pasipo na oksijeni (hewa), kinaweza kuongezeka ndani ya kina cha jeraha na kutoa sumu ya kutisha inayokaza misuli yote ya mwili","Kuacha jeraha refu hufupisha mguu wako miaka baadaye","Kutoka jeraha la zamani humea kucha mpya"],
    answerIndex:1,
    explanation:"Udongo na chuma kikuukuu chenye kutu huficha vijiviu (kama mayai) vya kijidudu kinachosababisha 'pepopunda'. Sifa kubwa ya kijidudu hiki ni kwamba ni 'kisichohitaji hewa': huchukia kugusa hewa. Kwa hiyo, badala ya jeraha la juujuu, mahali pake pendwa ni kina cha jeraha pasipofikiwa na hewa, kama la msumari uliochoma kwa kina. Jeraha likipona, kijidudu huongezeka kwa mlipuko katika giza la ndani ya ngozi na hutoa sumu kali inayoharibu neva za binadamu. Siku hadi wiki baadaye huja ugonjwa wa kutisha ambapo mdomo haufunguki tena, au misuli yote hujikunja nyuma na kupumua kunakuwa hakiwezekani. Unapoumia jeraha refu, lazima uwe na hekima ya kushauriana na hospitali kuhusu matibabu ya pepopunda." },
  { id:15, topic:"Mwanga mkali na macho", emoji:"👁️",
    question:"Baada ya kutazama moja kwa moja 'mwanga mkali', kama jua au cheche kali za kulehemu, kwa nini katikati ya uoni wako huendelea kumeta hata usione, hata ukifumba macho?",
    choices:["Mwanga mkali umevukiza machozi yote machoni mwako","Chembe za skrini muhimu zaidi ya ndani ya jicho inayonasa mwanga (retina) zilipata uharibifu mkubwa kama wa kuungua kwa nishati kupita kiasi, na neva ziko katika hofu","Chembe za mwanga zilinaswa ndani ya jicho na zinavurumika humo","Ubongo wako unakumbuka rangi ya mwanga"],
    answerIndex:1,
    explanation:"Ndani ya jicho la binadamu kuna skrini ya neva nyororo sana iitwayo 'retina', inayobadilisha mwanga unaoingia kuwa ishara za umeme na kuzipeleka ubongoni. Mwanga wa jua na mwanga mkali sana una nishati yenye nguvu ya uharibifu ya kutisha, kama 'miale ya urujuanimno'. Ukiitazama moja kwa moja kwa jicho tupu, kwenye retina yako mwenyewe hutokea sawa na pale kioo cha kukuza kinapokusanya mwanga wa jua kuchoma karatasi. Kumeta ni ushahidi kwamba chembe zinapiga kelele kwa kuwa zimeharibika. Likiwa kali, tundu hufunguka katikati ya retina (retinopathia ya jua), likiongoza kwenye upofu, ambapo uoni haurudi. Kuondoa macho kutoka mwanga mkali ndani ya sekunde moja ni kanuni ya sayansi ya kuyalinda." },
  { id:16, topic:"Meno ya watu wazima", emoji:"🦷",
    question:"Kwa nini usiache kamwe meno ya watu wazima ('meno ya kudumu') yanayoota karibu na madarasa ya juu ya shule ya msingi yapate mashimo (kuoza), sababu inayohusu maisha yote?",
    choices:["Jino la mtu mzima likioza, mifupa yote ya kichwa hulegea","Tofauti na meno ya maziwa, jino la kudumu likishaoza na kung'oka, jino jipya halitaota tena kutoka chini: ni sehemu ya mwili idumuyo maisha yote","Kupoteza jino la mtu mzima maana yake hutaweza tena kuzungumza kabisa","Jino lililooza huanza kusogea lenyewe usiku wa manane"],
    answerIndex:1,
    explanation:"Meno ya utotoni (ya maziwa) hubadilishwa hata yakioza, kwa kuwa meno mapya ya watu wazima husukuma kutoka chini. Lakini 'meno ya kudumu' yanayoota karibu na umri wa miaka 10 ni, kwa maana halisi, toleo la mwisho, yaliyotengenezwa kutumika hadi mwisho kabisa wa maisha. Tofauti na mkia wa mjusi au ngozi ya binadamu, enameli ngumu ya uso wa jino, ikishaharibiwa na kuyeyuka, haitarudi kamwe, asilimia 100, kwa umbo lake la awali kwa nguvu zake. Ukipoteza meno, huwezi tena kusaga chakula, jambo linaloleta uharibifu mkubwa kwa tumbo na utumbo, hudhoofisha lishe ya mwili mzima na hufupisha maisha. Kutunza vizuri meno yako ya mtu mzima ni kujipatia mwenyewe afya yako ya baadaye." },
  { id:17, topic:"Kulinda ubongo", emoji:"🚭",
    question:"Duniani kote, sheria inakataza kwa ukali watoto na vijana wadogo kuingiza miilini mwao 'pombe', 'tumbaku' au dawa za kulevya hatari zinazoharibu ubongo. Sababu ya kisayansi ni ipi?",
    choices:["Vitu hivyo ni haki ya pekee ya watu wazima kufurahia peke yao","Mwili wa mtoto bado unajenga kwa kasi 'mizunguko ya ubongo (mtandao)' hadi karibu miaka 20, na sumu ikiingia, ukuaji husimama kabisa na kumbukumbu na udhibiti wa hisia huvunjika milele","Watoto wakizitumia, rangi ya nguo zote inakuwa nyeusi","Hakuna sababu halisi; ni kanuni tu ambayo watu wazima wameitunga kuwabana watoto"],
    answerIndex:1,
    explanation:"Ubongo wa binadamu hutumia muda mrefu tangu kuzaliwa hadi karibu miaka 20 kila siku ukifanya kazi za kulaza mitandao tata ya chembe za neva, ili uwe na busara zaidi na uweze kudhibiti hisia vizuri zaidi. Sumu kama pombe, nikotini ya tumbaku, au dawa za kulevya kama bangi zikitiririka ubongoni katika kipindi hiki nyeti sana 'cha ujenzi unaoendelea', kazi ya nyaya huharibika kwa machafuko na ukuaji husimama kabisa. Matokeo yake, hata ukiwa mtu mzima huwezi tena kufikiri kwa kina, hulipuka na kusababisha vurugu, au unakuwa mwili wa kusikitisha usiowezi kuishi bila dawa (uraibu). Ili kulinda ubongo wako, shika azimio thabiti la kutokaribia kamwe sumu hizi maisha yako yote." },
  { id:18, topic:"Usingizi husafisha ubongo", emoji:"😴",
    question:"Unapoishi kila siku bila kulala vya kutosha, kwa nini watu huwa rahisi zaidi kuugua na hawawezi kufikiri kwa uwazi?",
    choices:["Usipolala, mifupa ya mwili huwa myepesi zaidi na huvunjika","Mfumo wa usafishaji unaosukuma taka hatari nje ya ubongo, na homoni ya ukuaji inayoponya majeraha ya mwili, vinavyofanya kazi tu wakati wa kulala, husimama kufanya kazi (mfumo wa glimfatiki)","Ukikwepa usingizi, jua hukasirika na kutoa joto","Binadamu asipolala, hugeuka kabisa kuwa roboti katika siku 3"],
    answerIndex:1,
    explanation:"Mchana, tunapoishi kwa kutumia vichwa vyetu, chembe za ubongo hutoa taka nyingi za protini hatari, kama 'beta-amiloidi', zinazojaa ndani ya kichwa. Mtu anapoingia usingizi wa kina usiku, chembe za ubongo hujikunja kidogo kutengeneza nafasi, na kwenye nafasi hizo 'majimaji ya ubongo-uti wa mgongo', maji safi, huingia kama tsunami, na kuanza usafi mkubwa unaosukuma mara moja taka za mchana. Huu ndio mfumo wa usafishaji wa ubongo uliogunduliwa na tiba ya kisasa. Ukikosa usingizi mara kwa mara, taka yenye sumu hubaki imerundikana kichwani, neva hufa na unakuwa mwenye hasira, kinga yako hushuka na hushindwa na kila ugonjwa. Usingizi ni sabuni bora zaidi ya ubongo." },
  { id:19, topic:"Jinsi urithi unavyofanya kazi", emoji:"🧬",
    question:"Katika nchi zote za dunia, na katika historia, kumekuwa na kanuni dhidi ya kuoana na kuzaa watoto na ndugu wa damu wa karibu sana (baba na binti, kaka na dada). Sababu ya kisayansi (ya kijenetiki) inayofanana ni ipi?",
    choices:["Kwa ndugu wa karibu, jina la mtoto atakayezaliwa haliwezi kuamuliwa","Kila mtu hubeba mahali fulani katika jeni zake 'kosa dogo la mchoro (chanzo cha ugonjwa)', na kati ya ndugu wa karibu makosa yale yale huingiliana, hivyo nafasi ya mtoto kuzaliwa na ugonjwa au ulemavu mzito hupanda kwa kasi","Kwa ndugu wa karibu, ndani ya nyumba huwa finyu","Mungu hapendi sura ya aina hiyo"],
    answerIndex:1,
    explanation:"Jeni, ambazo ni mchoro wa mwili wa binadamu, hutengenezwa kwa kupokea seti ya vitabu viwili: nusu kutoka kwa baba na nusu kutoka kwa mama. Kila mmoja hubeba kwa siri makosa machache 'makubwa ya mchoro' mahali fulani katika kitabu kimoja, lakini kama mchoro wa kitabu kingine ni sawa, unaweza kuishi kwa afya bila kuugua. Hata hivyo, binadamu walio karibu kwa damu hurithi michoro yao kutoka kwa mababu wale wale kabisa, hivyo 'mahali pa makosa yao' hufanana sana. Watu hawa wawili wakizaa mtoto, 'mchoro wenye hitilafu mahali pale pale kabisa' kutoka kwa baba na mama hukutana maradufu, kosa haliwezi tena kufunikwa, na mtoto mwenye ugonjwa au ulemavu mzito huzaliwa. Kutokana na uzoefu na hekima, binadamu wameunda kanuni ya kuepuka hatari hii." },
  { id:20, topic:"Kuongezewa damu na makundi", emoji:"🩸",
    question:"Kwa nini usimimine kamwe, kwa uamuzi wako usio wa kitaalamu, 'damu' yako moja kwa moja kwa sindano ndani ya mwili wa mtu aliyejeruhiwa vibaya ili kuigawa (kuongeza damu)?",
    choices:["Damu ya mwingine ikiingia, rangi ya nywele zako huwa kama yake","Damu ina makundi (A, B, O, AB), na aina tofauti zikichanganyika, chembe nyekundu hukataana kwa nguvu ndani ya mwili, hugandamana, huziba mishipa na humuua mtu","Kugawa damu hupunguza uzito wako kwa nusu","Kunywa damu ya mtu mwingine hukuletea maumivu ya tumbo"],
    answerIndex:1,
    explanation:"Damu yote huonekana kioevu chekundu kile kile, lakini uso wa chembe nyekundu una 'antijeni': alama maalumu (funguo na mihuri) zinazoonyesha aina ya damu hiyo. Hii ndiyo kundi la damu (mfumo wa ABO). Kwa mfano, ukimimina kwa kosa damu ya kundi B ndani ya mwili wa mtu wa kundi A, timu ya kinga ya kundi A hushtuka, 'adui nisiyewahi kumwona amevamia!', na hushambulia kwa pamoja chembe nyekundu zote za kundi B zinazoingia, ikizifumbatisha katika fundo gumu kama wavu (mwitikio wa kugandamana). Damu iliyoganda huziba mishipa minene ya mapafu na ubongo na husababisha kifo cha mshtuko papo hapo. Katika tiba, kipimo kinachochunguza kundi la damu ni uthibitisho wa uhai usioweza kuachwa kamwe." },
  { id:21, topic:"Kutafuna vizuri", emoji:"🍽️",
    question:"Unapoweka chakula mdomoni, kwa nini kutafuna vizuri kwa meno (zaidi ya mara 30) kabla ya kumeza husaidia sana kazi ya tumbo na utumbo, sababu ya kisayansi ni ipi?",
    choices:["Ukitafuna vizuri, chakula hutoweka kabisa mdomoni","Kusaga chakula kuwa vipande vidogo huongeza mara nyingi 'eneo la uso' la jumla, hivyo maji ya usagaji ya utumboni hupenya kote upesi na hunyonya virutubisho kwa ufanisi","Kutafuna hupandisha joto la tumbo hadi nyuzi 100","Kuzoeza meno hufanya misuli ya nyayo za miguu kuwa na nguvu"],
    answerIndex:1,
    explanation:"Huu ni utumiaji mzuri wa wazo la hisabati la 'eneo la uso'. Ukitupa donge kubwa la kiazi vile vile tumboni, asidi ya tumbo (asidi ya usagaji) huweza kuliyeyusha kutoka uso tu, hivyo huchukua saa nyingi kufika katikati, tumbo huchoka na hukuharibia tumbo. Lakini ukitumia meno kulitafuna kuwa makombo madogo, donge kubwa moja hugawanyika kuwa vipande maelfu vidogo. Kwa kugawanyika, 'jumla ya eneo' ambapo chakula huweza kugusa maji ya usagaji huongezeka kwa mlipuko. Kwa sababu hiyo, mara likifika tumbo na utumbo, maji hupenya hadi katikati papo hapo, huyeyusha chakula kuwa uji na hunyonya asilimia 100 ya virutubisho vya kuishi bila kuacha chochote. Kutafuna vizuri ni kiwanda cha kwanza cha kupika, kabla ya utumbo." },
  { id:22, topic:"Kukwama kooni (kuokoa)", emoji:"🍖",
    question:"Kipande kikubwa cha chakula kinapokwama kooni mwa mtu naye anakaba pumzi, unamkumbatia kutoka nyuma na kusukuma kwa nguvu juu kwenye tumbo lake (mbinu ya Heimlich). Ni nini lengo halisi la kusukuma tumbo?",
    choices:["Kubonyeza tumbo ndani ili aonekane mwembamba","Kushinikiza tumbo kwa nguvu husukuma juu hewa iliyobaki mapafuni, na kwa shinikizo hilo la hewa (nguvu ya bunduki ya hewa) hurusha nje kwa nguvu kitu kilichokwama kooni","Ili kushtua minyoo iliyo ndani ya tumbo","Ili kusukuma chakula kilichokwama chini, tumboni"],
    answerIndex:1,
    explanation:"Kitu kinapokwama kooni na mtu hawezi kupumua, kwa kweli ndani ya 'mapafu' bado kuna hewa nyingi isiyotolewa. Kati ya kifua na tumbo la binadamu kuna sakafu kubwa ya misuli iitwayo 'kiwambo', inayovimbisha na kukunja mapafu. Unapokumbatia kutoka nyuma na kusukuma kwa nguvu juu kidogo juu ya kitovu, viungo vya tumbo husukumwa juu, na kwa upande wake kiwambo hupiga mapafu kwa nguvu kutoka chini. Ndipo hewa iliyobaki mapafuni hurudi kooni papo hapo kama dhoruba kali na, kama bunduki ya hewa, hurusha nje kipande cha chakula kilichoziba koo. Ni mbinu ya ajabu ya kuokoa, inayotegemea fizikia, inayotumia muundo wa mwili wa binadamu." },
  { id:23, topic:"Vimelea na chakula kibichi", emoji:"🐛",
    question:"Kwa nini usile kamwe nyama mbichi ya wanyama-pori, wala kunywa maji mabichi ya mtoni, bila kuyapasha moto, sababu ya kutisha kuhusu minyoo izaayo ndani ya mwili wako?",
    choices:["Kula kibichi hugeuza mwili wa binadamu kuwa mnyama","Ndani ya miili ya viumbe na maji mabichi hujificha vimelea, vilivyojificha kama mayai yasiyoonekana, vinavyoingia utumboni mwa binadamu, huuma ukuta na huiba virutubisho au hula viungo","Maji mabichi hugeuza mifupa yote ya tumbo lako kuwa uji","Kula nyama mbichi hufanya sauti za wanyama zirudie mwangwi ndani ya tumbo lako"],
    answerIndex:1,
    explanation:"Maji ya mito ya asili, na nyama ya kulungu-pori, nguruwe-pori au nguruwe, huficha karibu asilimia 100 mayai na viluwiluwi vya 'vimelea' vidogo visivyoonekana (kama tegu na chango). Ukivila 'vibichi', hubaki hai hata katika asidi ya tumbo na hufika utumboni. Hapo mayai huangua, na virefu hukua kuwa minyoo mikubwa ya mita kadhaa inayoshikamana na ukuta wa utumbo na kunyonya virutubisho vyote ulivyokula ili kuishi, ikikuacha mwenye utapiamlo. Baadhi hujipenyeza ubongoni au ini na kuyeyusha viungo kuwa uji: minyoo mibaya inayohatarisha uhai wako. Vimelea ni dhaifu sana mbele ya moto (joto), kwa hiyo hekima ya usafi ni lazima kabisa: pika nyama vizuri hadi katikati, na chemsha maji ili kuviangamiza vyote." },
  { id:24, topic:"Maliza dawa yako", emoji:"💊",
    question:"Unapotumia 'antibiotiki' ulizopewa na daktari za kuua vijidudu mwilini, ni kanuni gani ya kutisha ya tiba lazima uifuate bila kukosa?",
    choices:["Homa ikishuka na ukajisikia vizuri, acha mara moja kwa uamuzi wako kwa kuwa dawa ni ghali","Hata dalili zikipungua na kuonekana umepona, zinywe zote hadi mwisho, idadi ya siku ulizoelekezwa, hadi vijidudu vya mwilini vifike sufuri","Badilisha wakati wa kunywa dawa kuwa saa tofauti kila siku kwa hiari","Rafiki akiwa na mafua, mgawie dawa yako iliyobaki"],
    answerIndex:1,
    explanation:"Unapoanza antibiotiki, kwanza vijidudu 'dhaifu na vingi vya kawaida' hufa kwa mpangilio. Baada ya nusu kufa, mwili hujisikia kama umepona kabisa. Ukiacha hapa ukifikiri 'nimepona', vile vichache 'vijidudu vibaya na vikaidi zaidi vilivyostahimili shambulio la dawa' vilivyokuwa bado vinaishi kwa shida hufufuka na kuanza kuzaliana kwa wingi tumboni tena. Kwa kuwa vijidudu hivi vilishapitia shambulio na kunusurika, vimegeuka kuwa vijidudu vya kinyama (bakteria sugu) vyenye ngao yenye nguvu kupita kiasi ambayo dawa haiwezi tena kuishinda. Ndipo, hata ukinywa dawa ile ile, haifanyi kazi kabisa, hakuna tiba iliyobaki, na huongoza kifoni. Kuendelea kunywa dawa bila kulegeza hadi kuviangamiza kabisa, hii ndiyo kanuni ngumu ya tiba inayolinda dunia." },
  { id:25, topic:"Jinsi baridi kali ya ngozi itokeavyo", emoji:"🥶",
    question:"Unapokaa muda mrefu mahali penye baridi kali sana, kama mlima wa theluji au juu ya barafu, kwa nini ncha za vidole vya mikono na miguu hugeuka rangi ya zambarau na kupoteza hisia (baridi kali ya ngozi)?",
    choices:["Upepo baridi hupaka uso wa ngozi yako rangi ya zambarau","Ili kulinda joto la moyo na viungo muhimu zaidi (kitovu cha mwili), ubongo hubana mishipa ya ncha za vidole na hukusanya damu katikati tu","Mahali penye baridi, damu yote ya mwili huganda kwa pamoja na kuacha kusogea","Ncha za vidole vya mikono na miguu zimelala kwa baridi"],
    answerIndex:1,
    explanation:"Huu ni ushahidi wa mfumo wa ulinzi wa kikatili, lakini wa hali ya juu kabisa wa kunusurika, ulio nao ubongo wa binadamu. Mwili mzima unapowekwa kwenye baridi kali ya kuganda, kama damu ingeendelea kutiririka kama kawaida hadi ncha za vidole, damu iliyopozwa pale ingerudi moyoni, ikishusha joto la moyo na ubongo (joto la ndani) na kusababisha kifo cha papo hapo kwa baridi. Ili kuzuia hili, ubongo huamuru: 'Toa kafara ncha za vidole ikibidi, lakini usiache kamwe mwali wa uhai wa moyo wa katikati uzimike!' Ndipo mishipa ya mikono na miguu hufunga kwa nguvu na damu huacha kuzifikia. Ncha za vidole, zisizopata damu (oksijeni), chembe zake hufa na kugeuka zambarau, na katika hali mbaya zaidi huoza na kudondoka (baridi kali ya ngozi). Mahali penye baridi, endelea kusogeza mikono na miguu, badilisha glavu zilizolowa mara moja, na uzuie ubongo kutoa amri ya kuachilia mikono na miguu." },
  { id:26, topic:"Giza na macho", emoji:"🌙",
    question:"Wakati unaingia usiku katika chumba chenye giza totoro kisicho na umeme, huoni chochote, lakini ukisimama kimya hapo kama dakika 10, maumbo ya samani na kuta zinazokuzunguka huonekana kwa ukungu. Kwa nini?",
    choices:["Kutoka jicho la binadamu huanza kutoka wenyewe mwale wa mwanga usioonekana","Tundu jeusi katikati ya jicho (mboni) hufunguka wazi gizani na hubadilisha umbo ili kukusanya kadiri iwezekanavyo mwanga hafifu uliopo karibu (kama wa nyota) (kuzoea giza)","Ubongo hufikiria mwenyewe mandhari ya giza na huonyesha njozi","Muda ukienda, rangi ya giza la usiku hupungua"],
    answerIndex:1,
    explanation:"Tundu jeusi katikati ya jicho la binadamu huitwa 'mboni', na kama tundu la lenzi ya kamera, lina pazia la misuli linalorekebisha lenyewe kiasi cha mwanga unaoingia jichoni. Mahali penye mwanga, kama chini ya jua, mboni hujikunja ndogo kama ncha ya sindano ili mwanga uliozidi usichome jicho. Kutoka hapo ukihamia ghafla mahali penye giza totoro, mwanzoni mwanga hautoshi na huonekana jeusi kabisa. Lakini kwa muda wa kama dakika 10, pazia hili la mboni hufunguka hadi kikomo na huanza kwa juhudi kukusanya chembe hafifu za mwanga, nyembamba mno kuonekana, katika pembe za chumba. Mfumo huu huitwa 'kuzoea giza'. Hata ukiwa katika dhiki gizani, usishtuke: kwa kufumba macho na kusubiri kimya dakika 10, unaweza kurudisha dira ya uoni wako. Hii ni hekima ya mwili wa binadamu." },
  { id:27, topic:"Sayansi ya kuvaa tabaka", emoji:"🧥",
    question:"Ili kujikinga na baridi katika msimu wa baridi sana, kwa nini ni joto zaidi kuvaa tabaka nyingi nyembamba (kwa tabaka) kuliko kuvaa nguo moja nene kubwa?",
    choices:["Nguo nyingi hufanya mavazi mazito, hivyo hunyonya joto kutoka ardhini","Kati ya tabaka na tabaka hutengenezwa tabaka nyingi za hewa tulivu (kizuizi), kitu cha polepole zaidi duniani katika kupitisha joto, zinazozuia kabisa joto la mwili wako lisitoke nje","Nguo nyingi nyembamba zikisuguana, ndani huwaka moto","Kuvaa nguo nyingi hufanya upepo uzizunguke na kuziepuka"],
    answerIndex:1,
    explanation:"Hii pia ni hekima nzuri ya kisayansi inayotumia tabia za maada. Maada yenye nguvu zaidi duniani kwa ugumu wa kupitisha joto (kwa kuzuia joto) ni kwa kweli hewa tulivu (gesi). Hata ukivaa nguo moja nene, joto la mwili lenye uvuguvugu ndani husafiri kupitia nyuzi za nguo na kutoroka nje. Lakini ukivaa nguo nyembamba 3 au 4 kwa tabaka, katika nafasi kati ya nguo hutengenezwa 'vyumba vingi vya hewa iliyofungiwa kabisa isiyoweza kusogea'. Tabaka hili la hewa hutenda kama 'kizuizi', sawasawa na ukuta wa chupa ya joto (thermos), na huwa kizuizi chenye nguvu zaidi kisichoacha joto lako la nyuzi 36 litoke wala hewa baridi ya kuganda iingie. Usipokuwa na nguo, hata kujaza gazeti kavu au majani makavu ndani ya nguo hutengeneza tabaka la hewa lile lile na kunaweza kulinda uhai wako dhidi ya kufa kwa baridi." },
  { id:28, topic:"Pigana au kimbia", emoji:"🏃",
    question:"Mnyama mla-nyama mkali anapotokea ghafla mbele yako, au unapokumbana na janga kubwa, kwa nini moyo wako ghafla hupiga kwa nguvu sana na unatoka jasho baridi, bila wewe kutaka?",
    choices:["Ni ishara kwamba moyo umeshtuka kwa woga, umeharibika na uko karibu kusimama","Ili kunusurika, ubongo huanza kujiandaa 'kupigana sasa hivi au kukimbia kwa nguvu zote', na kwa mlipuko hupeleka kiasi kikubwa cha oksijeni (damu) kwenye misuli ya mwili mzima (mwitikio wa pigana-au-kimbia)","Katika janga, kiasi cha damu mwilini huongezeka maradufu","Ili kufanya moyo uwe na kelele kumshtua adui aliye mbele hadi azimie"],
    answerIndex:1,
    explanation:"Binadamu anapohisi woga au janga la kukata tamaa, kituo cha amri cha dharura kilicho ndani ya ubongo (amigdala) hutambua hatari papo hapo na hutoa kwa pamoja homoni maalumu iitwayo adrenalini damuni. Mara homoni hii ifikapo, pampu ya moyo hubadilika kwenda mwendo wa kasi sana wa nguvu zote, hupandisha mpigo kwa kishindo, na huharakisha kupeleka kiasi kikubwa cha oksijeni (damu) kwenye 'misuli ya miguu na mikono' ya kupigana au kukimbia kutoroka. Wakati huo huo, hubana mishipa ya ngozi ili kupunguza kutokwa damu iwapo utajeruhiwa, hivyo uso hubadilika rangi na jasho baridi hutoka. Katika lugha ya tiba, hii huitwa 'mwitikio wa pigana-au-kimbia'. Moyo wako kupiga kwa nguvu ni ishara bora zaidi ya ulinzi: mwili wako, ili kukulinda, umetoa nishati yake yote na umegeuka kuwa hali ya mapigano." },
  { id:29, topic:"Kazi ya vitamini", emoji:"🍊",
    question:"Hata ukijaza tumbo kila siku kwa wali na viazi vingi, kwa nini huugua (kwa mfano kiseyeye), na damu hububujika kutoka mishipani mwili mzima, ikiwa kwa miezi hutaki kula mboga au matunda mabichi kabisa?",
    choices:["Usipokula mboga, rangi nyekundu yote ya damu hutoweka","Virutubisho vikuu vitatu (kama wanga) havitoshi; vitamini, vinavyotenda kama gundi inayoshikamanisha chembe imara na kama kilainishi kinachosaidia athari za kemikali, hukauka","Mwili wa asiyekula matunda una kanuni ya minyoo kuula kutoka ndani","Tumbo lako huacha kufanya kazi lisipoona rangi ya kijani ya mboga"],
    answerIndex:1,
    explanation:"Binadamu anaweza kunenepa kwa kula wali na mkate (wanga), lakini hilo peke yake haliwezi kamwe kumtunza akiwa na afya. Ili kuweka trilioni za chembe na kuta za mishipa ya mwili katika hali yenye ulaini na afya, lazima kabisa uhitaji 'vitamini' (hasa vitamini C na nyingine), virutubisho-vidogo ambavyo mwili hauwezi kuvitengeneza wenyewe. Vitamini ni vipuri visivyoepukika kwa kutengeneza 'kolajeni (gundi ya chembe)' inayojenga mwili. Vikipungua kwa miezi, gundi ya chembe za mwili mzima hukatika vipande vipande, mishipa midogo sana ya fizi, ngozi na viungo hupasuka kila mahali, na damu huvuja taratibu kutoka ndani: ugonjwa wa kutisha wa 'kiseyeye', na mwishoni hufa. Si kujaza tumbo tu, bali kuchukua kiasi kidogo cha vitamini na madini, hiyo ndiyo kweli ya lishe inayodumisha mfumo wa uhai." },
  { id:30, topic:"Homa ni ulinzi", emoji:"🤒",
    question:"Vijidudu vya mafua au maambukizi vinapoingia mwilini, mwili hutetemeka na homa kali ya zaidi ya nyuzi 38 hutokea. Kwa nini usishushe homa kwa nguvu kwa dawa mara moja, sababu ya kitabibu ni ipi?",
    choices:["Kushusha homa ghafla hugeuza maji yote ya mwili kuwa maji ya moto","Homa ni mwitikio sahihi wa ulinzi: ubongo hupandisha joto kwa makusudi ili timu ya kinga ipigane vizuri zaidi na kusimamisha kuzaliana kwa vijidudu na virusi, ambavyo ni dhaifu kwa joto","Kushusha homa hufanya nywele zote za kichwa zinyonyoke","Unapokuwa na homa kali, kasi yako ya kukimbia huongezeka"],
    answerIndex:1,
    explanation:"Hongera! Kwa hili, maswali 30 ya kwanza ya 'Wise World 3' yamekamilika. Watu wengi huelewa vibaya kwamba 'homa ni kitu kibaya, shusha mara moja', lakini huo ni mkosi mkubwa. Vijidudu na virusi vingi vinavyovamia mwili hupenda joto la kawaida la binadamu la 'karibu nyuzi 36' na huzaliana hapo kwa mlipuko zaidi. Lakini joto linapopanda hadi nyuzi 38-39, msogeo wa virusi hupooza na haviwezi tena kuzaliana. Kinyume chake, timu yetu ya kinga, kama chembe nyeupe za damu, husogea kwa nguvu na kasi mara nyingi zaidi wakati joto la mwili liko juu. Yaani homa ni mkakati wa ubongo wa kupandisha kwa makusudi 'joto la chumba' ili kupata ushindi katika vita. Kupoza kichwa, kuchukua maji mengi, na kuilinda homa ambayo mwili wako unapigania, bila kuishusha kwa nguvu, na kupumzika, hiyo ndiyo hekima bora zaidi ya tiba ya kunusurika ili isiwe ugonjwa mzito." },
  { id:31, topic:"Faida ya mgawanyo wa kazi", emoji:"🛠️",
    question:"Wakati watu wazima wa jamii hawafanyi wote kazi ile ile, bali wanagawanyika katika kazi tofauti kama mkulima, seremala, na daktari ('mgawanyo wa kazi'), faida kubwa zaidi ni ipi?",
    choices:["Wote wakifanya kazi ile ile, inakuwa vigumu kukumbuka nyuso za kila mmoja","Unaondoa kikomo cha muda cha mtu mmoja kujifunza vyombo na ujuzi vyote kutoka sufuri, na kila mtaalamu akishirikiana, uzalishaji wa jamii nzima unalipuka juu","Kufanya mgawanyo wa kazi kunaongeza maradufu saa za kazi kila siku","Kadiri aina za kazi zinavyozidi, ndivyo inavyoonekana yenye shamrashamra na furaha"],
    answerIndex:1,
    explanation:"Kama hapakuwa na mgawanyo wa kazi, ungelazimika kuotesha mwenyewe ngano unayoila, kujenga mwenyewe nyumba unayoishi, na ukiugua, kutengeneza mwenyewe dawa. Hivi saa za siku hazingetosha kamwe, kila kitu kingebaki nusu, na kuishi kwa wingi kungekuwa haiwezekani. Binadamu walibuni hekima kubwa zaidi, 'mgawanyo wa kazi', ambapo kila mmoja anajikita katika kazi moja na kukamilisha ujuzi wake, na kubadilishana bidhaa na huduma zilizotengenezwa. Hii inaruhusu kuzalisha matokeo bora mara nyingi kwa juhudi kidogo, na huunda jamii tajiri ambapo tunashikiliana uhai kwa ufanisi wa juu kabisa." },
  { id:32, topic:"Pesa ni uaminifu", emoji:"💵",
    question:"Noti za karatasi (sarafu) tunazotumia kila siku ni vipande vya karatasi tu, basi kwa nini tunaweza kuzitumia kubadilisha kwa chakula kitamu na vyombo vizuri?",
    choices:["Ndani ya karatasi hiyo kuna kiungo cha kichawi kinachoshibisha tumbo","Kwa sababu kila mtu katika jamii anaweka kwenye noti hiyo 'uaminifu' wa pamoja: 'nikitoa karatasi hii, daima nitaweza kuibadilisha kwa bidhaa za thamani ile ile'","Kwa sababu sheria inasema mchoro wa noti ndio mzuri zaidi duniani","Kwa sababu uzito wa karatasi ni kama bonge la chuma"],
    answerIndex:1,
    explanation:"Asili ya kweli ya pesa (sarafu) si thamani yake kama kitu, bali ni 'mfumo wa uaminifu' kati ya watu. Zamani sana watu walibadilishana dhahabu na fedha zenyewe, lakini zilikuwa nzito na za usumbufu kubeba, hivyo nchi na jamii zilitengeneza chombo cha karatasi cha pamoja, 'noti', ambacho zinakihakikishia uaminifu. Kwa sababu ahadi na uaminifu vilivyo vichwani mwa wote vinapatana - 'hata nikipokea noti, nitaweza kuitumia vivyo hivyo dukani lijalo' - kipande cha karatasi tu kina nguvu yenye uwezo wa kubadilishwa kwa bidhaa. Katika jamii ambayo uaminifu umeporomoka, noti zinabadilika, kihalisia, kuwa vipande visivyo na thamani." },
  { id:33, topic:"Kipimo cha thamani", emoji:"📏",
    question:"Ikilinganishwa na maisha ya kubadilishana bidhaa, mfumo gani rahisi na wa haki ulizaliwa kwa kuingiza 'pesa (sarafu)' katikati ya kununua na kuuza?",
    choices:["Kutumia pesa kunashusha uzito wa bidhaa zote nusu","Thamani ya bidhaa zote inaweza kuonyeshwa kwa rula ya pamoja iitwayo 'namba', hivyo hata bidhaa za aina tofauti zinaweza daima kulinganishwa kwa bei kwa haki na kufanyiwa biashara (kipimo cha thamani)","Kutumia pesa kunamaanisha muuzaji daima anakupa zawadi","Muda wa muamala daima unakuwa sekunde 1 sawasawa"],
    answerIndex:1,
    explanation:"Pesa ina jukumu muhimu la 'kipimo cha thamani', kupima thamani ya bidhaa zote kwa namba. Katika dunia ya kubadilishana bidhaa bila pesa, ungelazimika kujadiliana na mwingine kila mara - 'kondoo huyu ni sawa na samaki wangapi, magunia mangapi ya ngano, mashoka mangapi?' - na hesabu ingekuwa fujo. Lakini pesa, rula ya pamoja, ilipoonekana katikati, kila kitu kingeweza kulinganishwa kwa namba ile ile, kama 'kondoo ni sarafu 10,000, samaki ni sarafu 500'. Kwa hii wote waliweza kufanya biashara kwa haki na kwa wepesi, bila mkanganyiko na bila hasara." },
  { id:34, topic:"Hifadhi ya thamani", emoji:"💰",
    question:"Unapopata chakula kingi kama samaki na mboga, kwa nini ni bora kukibadilisha mara moja kuwa 'pesa (sarafu)' na kukiweka akiba, kuliko kukiweka kama kilivyo?",
    choices:["Kuweka pesa akiba kunafanya nguvu zibubujike zenyewe kutoka ndani ya mwili","Chakula kinaoza katika siku chache na thamani yake inakuwa sufuri, lakini kwa kukibadilisha kuwa pesa unaweza 'kuhifadhi tunda la kazi yako kwa miaka bila kukiacha kioze' (hifadhi ya thamani)","Kukibadilisha kuwa pesa kunaongeza maradufu kiasi cha chakula","Ukiweka pesa mfukoni, inang'aa yenyewe"],
    answerIndex:1,
    explanation:"Kazi kubwa ya tatu ya pesa ni 'hifadhi ya thamani'. Hata ukifanya kazi kwa bidii na kuvuna kiasi kikubwa cha samaki au ndizi, ukiviacha kama vilivyo vinaoza katika siku chache, na fuwele ya juhudi yako inatoweka. Hivi huwezi kuweka akiba ya wingi kwa mgogoro wa baadaye (njaa au jeraha). Lakini kwa kubadilisha mavuno haraka kuwa pesa, 'chombo kisichooza', unaweza kuhifadhi thamani uliyoifanyia kazi, sawasawa, kama kapsuli ya wakati, hata miaka kumi mbele. Pesa ni ghala salama la kulinda nafsi yako ya baadaye." },
  { id:35, topic:"Uhamisho wa thamani", emoji:"👛",
    question:"Katika biashara, badala ya kubeba viazi vizito au ng'ombe kama vilivyo, faida nzuri ni ipi, kwa upande wa kuhama, ya kufanya biashara kwa kutumia 'pesa (sarafu)'?",
    choices:["Kuwa na pesa kunafanya miguu yako ikimbie mara mbili zaidi","Unaweza kuiweka kwenye pochi au mfuko mdogo na 'kubeba thamani ya mali yako kwa wepesi hadi mahali popote pa mbali' (uhamisho wa thamani)","Pesa inaelea juu ya maji, hivyo unaweza kuvuka bahari kwa kuogelea","Kwenda mbali kunafanya thamani ya pesa iongezeke yenyewe"],
    answerIndex:1,
    explanation:"Pesa ina kazi ya 'uhamisho wa thamani'. Ukitaka kwenda mji wa mbali na kununua dawa adimu au chombo imara, bila pesa ungelazimika kuburuza kwa miguu siku nyingi mazao mazito au ng'ombe wa mifugo. Hatari ya kushambuliwa na wezi njiani au ng'ombe kufa ni kubwa sana. Lakini ukibadilisha wingi huo mara moja kuwa umbo jepesi na dogo - noti au sarafu - unaweza kuificha kwenye pochi na kubeba kwa usalama thamani kubwa hadi nchi ya mbali papo hapo na kufanya biashara. Ni miundombinu yenye nguvu ili uchumi uvuke mipaka." },
  { id:36, topic:"Mkataba", emoji:"📝",
    question:"Unapotoa ahadi ya kazi na mtu, au kununua na kuuza bidhaa, kwa nini lazima daima uache 'mkataba' ulioandikwa kwenye karatasi, si ahadi ya mdomo tu?",
    choices:["Kuandika mikataba mingi kunazoeza misuli ya mkono na kukufanya mwenye nguvu","Kumbukumbu ya binadamu inakuwa fifi na kubadilika kwa wakati, hivyo kufunga maudhui ya ahadi kwa maandishi kunazuia baadaye mizozo ya 'ulisema, hukusema' na udanganyifu, na kukulinda","Ahadi iliyoandikwa Mungu anaitimiza kiotomatiki kwa uchawi","Kushikilia hati ya karatasi kunakufanya uonekane muhimu"],
    answerIndex:1,
    explanation:"Mojawapo ya hati muhimu zaidi za kunusurika katika jamii ni 'mkataba'. Hata rafiki wa karibu kiasi gani au mtu mzima aonekane wa kuaminika kiasi gani, hupaswi kumaliza kwa mdomo tu ahadi kama 'nitalipa kiasi hiki cha pesa baada ya miezi kadhaa' au 'nitamaliza kazi hii hadi wakati huo'. Kwa wakati, hakika atatokea mtu anayeandika upya kumbukumbu yake kwa manufaa yake au anayedanganya ili kujiepusha. Kwa kuacha ushahidi ulioandikwa wenye saini na muhuri za wote wawili, hata mwingine akivunja ahadi, unaweza kuomba nguvu ya watu wazima wa karibu au sheria na kujilinda kihalali. Mkataba ni fulana ya kuzuia risasi ya kutembea salama katika ulimwengu wa watu wazima." },
  { id:37, topic:"Mahitaji na ugavi", emoji:"⚖️",
    question:"Sokoni, mavuno ya maharagwe fulani yalishuka sana kwa sababu ya mvua kubwa, na idadi ya maharagwe duniani ikawa ndogo sana. Lakini idadi ya wanaoyataka ni kubwa. Wakati huu, bei ya maharagwe inabadilikaje?",
    choices:["Kwa kuwa ni machache na hakuna anayeweza kununua, bei inakuwa sufuri","Inakuwa mvutano kati ya wanaoyataka, na wanaongezeka wanaokubali kulipa pesa zaidi ili kununua, hivyo bei ya maharagwe 'inapanda ghafla kwa kasi'","Lolote litokee, bei ya bidhaa zote daima ni thabiti duniani kote","Maharagwe yanakua kwa ukubwa na bei inashuka kidogo"],
    answerIndex:1,
    explanation:"Hii ni sheria kamili iliyo msingi zaidi wa uchumi: 'mahitaji (kiasi kinachotakiwa) na ugavi (kiasi kinachouzwa)'. Bei ya bidhaa haiamuliwi kwa hamaki ya mtu, bali kiotomatiki kwa usawa (mizani) wa hivi viwili. Idadi ya wanaotaka kununua (mahitaji) inapokuwa kubwa kupita kiasi kuliko idadi ya bidhaa za kuuza (ugavi), thamani ya bidhaa (thamani ya uadimu) inaruka juu. Ukijua mfumo huu, unaweza kwa utulivu kutabiri mbele - 'kipi kinakosekana sasa na kipi kinatafutwa' - na kuweka mpango wa biashara unaotatua kwa werevu matatizo ya jamii." },
  { id:38, topic:"Maana ya faida", emoji:"📈",
    question:"Ni nini maana ya kweli ya kimsingi katika jamii ya kupata 'faida' kwa kufanya biashara?",
    choices:["Kudanganya wengine pia, kuishi kwa raha na anasa wewe mwenyewe pekee","Kama matokeo ya kutatua kinachowasumbua wengine (usumbufu au wasiwasi) kwa hekima na kazi yako, kupokea kwa haki thamani inayozidi gharama uliyotumia (gharama ya kununua), kama 'malipo ya msaada wako na shukrani yao'","Kupokea pesa kutoka kwa nchi mwenyewe na kuziweka mfukoni","Kufanya jina la duka lako mashuhuri zaidi duniani"],
    answerIndex:1,
    explanation:"Kupata faida katika biashara si jambo baya kamwe, wala kunyang'anya pesa kwa mtu. Faida inahesabiwa kama '(bei ya kuuza) toa (gharama ya kununua au ya kutengeneza)'. Mfano, kwa asiyeweza kwenda chemchemi safi ya mbali, wewe unabeba ndoo na kuteka maji badala yake, na unagawa kwa sarafu 20 maji uliyonunua kwa 10. Faida ya sarafu 10 ya tofauti hii ni malipo ya shukrani ya haki kwa kuwa umeondoa 'usumbufu wake wa kuhama'. Kadiri unavyotatua maumivu ya mtu katika jamii, ndivyo uaminifu uitwao faida unavyokusanyika mikononi mwako." },
  { id:39, topic:"Kazi ya benki", emoji:"🏦",
    question:"Ni nini lengo la kimsingi zaidi ambalo kwalo mahali palipozaliwa zamani liitwalo 'benki' palithaminiwa na watu wa jamii na kuendelea?",
    choices:["Kupamba chumba kwa noti nyingi nzuri na kuzitazama","Kwa kuwa kuweka pesa nyingi nyumbani kunahatarisha kuibwa na wezi, ili pesa 'zihifadhiwe kwa usalama (akiba)' katika sefu imara, na kufanya uhamisho salama (malipo) hadi miji ya mbali","Kuweka pesa akiba kunaongeza ukubwa wa noti yenyewe","Kutangaza kwa wote ni nani mwenye pesa nyingi zaidi na kujivuna"],
    answerIndex:1,
    explanation:"Lengo la kwanza la kuzaliwa kwa benki ni 'hitaji la kuhifadhi kwa usalama'. Kuhifadhi sarafu za dhahabu au noti nyingi nyumbani kwako kuna hatari kubwa za kuteketea katika moto, au kushambuliwa na wanyang'anyi na hata kupoteza uhai. Hivyo ulitengenezwa mfumo wa 'kuweka' pesa mahali penye sefu na ulinzi imara zaidi katika jamii. Ukiweka pesa benki, zinakuwa kumbukumbu ya namba katika kijitabu, na unaweza kulinda mali yako ya thamani 100% dhidi ya wizi. Ni ngome ya hekima inayosimamia pesa kwa usalama si kama 'bonge la karatasi la kimwili', bali kama 'namba zinazoaminiwa'." },
  { id:40, topic:"Deni na riba", emoji:"💸",
    question:"Unapokopa 'pesa (deni)' kutoka kwa mtu mwingine au benki, ni mfumo gani wa kiuchumi wa kutisha usiopaswa kuusahau kamwe?",
    choices:["Kukopa pesa kunafupisha kimo chako kidogo","Si tu kurudisha pesa uliyokopa (rasilimali) kama ilivyo, bali badala ya muda uliokopa, lazima daima uongeze pesa za ziada juu (riba) na urudishe zaidi","Sheria kwamba ukishakopa pesa, huruhusiwi kununua tena kamwe","Kwamba pesa uliyokopa unaweza kuifanya yako bila kuirudisha"],
    answerIndex:1,
    explanation:"Kukopa pesa ni 'kukopa kabla' kazi na uhuru wa nafsi yako ya baadaye. Deni daima lina ada ya kukodi iitwayo 'riba' au 'kiwango'. Mfano, ukikopa sarafu 10,000 na sheria ya riba ni 10%, baadaye lazima urudishe sarafu 11,000. Ukidharau mfumo huu wa riba, kadiri unavyolipa, hesabu ya riba inazidi kuvimba (kama mpira wa theluji), na unaishia maisha kama mtumwa, ukilipa pesa kwa ajili ya wengine maisha yako yote. Isipokuwa una mpango wa hakika wa kukuza pesa, lazima uepuke kabisa deni la urahisi." },
  { id:41, topic:"Uwekezaji na matumizi", emoji:"🌱",
    question:"Kuna njia mbili za kutumia pesa. Tofauti na 'matumizi', kununua peremende unazokula sasa zinazotoweka papo hapo, ni upi mfano halisi wa 'uwekezaji', kutumia pesa kuongeza nguvu na wingi wako wa baadaye?",
    choices:["Kununua nguo nyingi zenye kung'aa za mtindo wa hivi punde","Kununua 'chombo' imara cha kuanzisha kazi mpya yako, au kutumia pesa kwa 'vitabu (kusoma)' ili kupata maarifa","Kumwaga pesa zako zote kwenye kamari ya kasino au michezo","Kuweka pesa juu ya sahani na kuzikodolea macho tu"],
    answerIndex:1,
    explanation:"Ukitumia pesa tu (matumizi/ubadhirifu), pesa zinatoweka tu kutoka mikononi mwako na mwisho. Lakini mwenye hekima anatumia pesa kama 'mbegu (uwekezaji) ya kuzidisha nguvu yake ya baadaye mara nyingi'. Mfano, aliyekuwa akichonga mbao kwa mkono akiweka akiba na kununua shoka bora (chombo), kuanzia kesho anaweza kutengeneza kuni mara 10 kwa muda ule ule, na pesa zinazoingia zinaongezeka kwa kasi. Pia kununua na kusoma vitabu vya tiba au sayansi ni 'uwekezaji binafsi' wenye nguvu zaidi, unaobadilisha ubongo wako kuwa chombo bora cha kuchuma. Sogea ukihesabu utumie pesa kwa nini ili mustakabali wako uwe tajiri." },
  { id:42, topic:"Kodi na bidhaa za umma", emoji:"🌉",
    question:"Kwa nini mfumo ni wa lazima kabisa ambapo kila mtu katika kijiji au mji anachangia kidogo kidogo sehemu ya pesa anayochuma - 'kodi' au pesa zinazokusanywa (fedha za jamii)?",
    choices:["Kutumia pesa zilizokusanywa na kufanya sherehe kubwa kila siku wote pamoja","Kudumisha wote pamoja 'kisima cha pamoja, barabara imara, madaraja makubwa, na hospitali zinazookoa wagonjwa (bidhaa za umma)' ambazo pesa za mtu mmoja hazingeweza kamwe kutengeneza, na kulinda jamii","Kukusanya pesa nyingi na kuzizika ndani sana ardhini","Kufanya nyumba ya kiongozi fulani muhimu ya kifahari kama kasri"],
    answerIndex:1,
    explanation:"Kama jamii haingekuwa na kodi wala pesa zinazochangwa pamoja (fedha za umma) kabisa, hakuna mtu mmoja angeweza kulipa pesa kubwa kujenga daraja kubwa au kusakafia barabara ndefu. Barabara zikiwa mbovu, hakuna anayeweza kuhama kwa hofu ya kuumia, na biashara na maisha vinaporomoka kabisa. Ndio maana wote wanachangia kidogo na kuzikusanya, kujenga na kudumisha 'miundombinu ya pamoja ambayo hakuna anayeweza kuijenga peke yake (bidhaa za umma)'. Mfumo huu wa kusaidiana (usalama wa kijamii na msaada wa umma) ndio msingi wenyewe wa ustawi unaolinda usalama wa dunia." },
  { id:43, topic:"Thamani ya kufanya kazi", emoji:"💪",
    question:"Ni nini thamani ya kimsingi na kubwa zaidi, kama binadamu, ya 'kufanya kazi (kuhangaika)' katika jamii?",
    choices:["Kuamriwa na mtu na kusogeza mwili tu kama roboti","Kutumia nishati yako nzuri ya 'muda, ujuzi, na hekima' kutatua 'usumbufu au tatizo (maumivu)' la mtu katika jamii na kufanya dunia bora kuliko jana","Kufanya kazi saa zaidi ya wengine, kuvunja mwili, na kujivuna","Kupata ruhusa ya kufanya lolote mradi unapokea pesa"],
    answerIndex:1,
    explanation:"Sura ya kweli ya kufanya kazi si kazi ya kupokea pesa tu. Ni kitendo cha kuumba thamani: kutoa kwa jamii muda wako wa thamani wa uhai na ujuzi wako na kubadilisha 'niko taabani!' la mtu kuwa 'asante Mungu!'. Mkulima akitengeneza chakula kitamu anafuta njaa, na daktari akitoa matibabu anafuta maumivu. Kupitia kufanya kazi, unahitajika ndani ya jamii na kuwa kipande muhimu cha fumbo kinachoshikilia uhai wa mtu. Kujua lengo la kufanya kazi kwa usahihi kunaimarisha fahari ya maisha yako na miguu ya kujitegemea kwako." },
  { id:44, topic:"Hatari ya ukiritimba", emoji:"👑",
    question:"Wakati kuna 'duka moja tu' linalouza dawa fulani muhimu sokoni (ukiritimba), kwa nini ni hatari sana kwa mnunuzi?",
    choices:["Kwa duka moja tu, kukumbuka jina la duka kunakuwa usumbufu","Kwa kuwa hakuna mshindani wa kushindana, hata mwenye duka akipandisha bei kwa udhalimu hadi 'bei kubwa mno', mnunuzi hana chaguo ila kulipa pesa hiyo kubwa ili aishi","Kwa duka moja, umbo la dawa linabadilika kuwa pembetatu lenyewe","Hakuna hatari; duka moja ni salama zaidi daima"],
    answerIndex:1,
    explanation:"Hali isiyokuwa na mshindani hata mmoja sokoni inaitwa 'ukiritimba'. Ukiritimba ukitokea, mizani nzuri ya mahitaji na ugavi inavunjika, na muuzaji anaweza kudhibiti bei kwa uhuru kama mungu. Hata dawa inayopaswa kuuzwa sarafu 10 ikiambiwa 'ni sarafu 10,000; kama hupendi, usinunue na uugue', unyonyaji unatokea ambapo mali yako yote inanyang'anywa ili uishi. Ndio maana jamii yenye afya inalinda mfumo wa 'ushindani', ambapo kuna maduka kadhaa yanayouza bidhaa zinazofanana na kushindana, na kuweka kizuizi ili bei zisipande kwa udhalimu." },
  { id:45, topic:"Mtego wa kizuri mno", emoji:"🎣",
    question:"Mtu mzima asiyejulikana alikupa mwaliko mtamu: 'Ukinisaidia kazi hii, nakupa papo hapo kiasi kikubwa cha pesa ambacho hujawahi kuona'. Ufanye nini?",
    choices:["Kwa kuwa ni fursa ya kupata kiasi kikubwa, kusaidia mara moja bila kufikiri","Kukataa kabisa na kuondoka mahali hapo. Katika dunia hii, 'kazi isiyo na hatari ambapo unapata kiasi kikubwa kwa urahisi' 100% haipo kamwe; ni mtego wa kukufanya ubebe sehemu ya uhalifu na kuharibu maisha yako","Kualika marafiki wengi na kufanya kazi hiyo wote pamoja","Kutengeneza papo hapo mkataba wa karatasi wa kiasi utakachopokea"],
    answerIndex:1,
    explanation:"Sheria baridi na kamili ya uchumi ni 'ukubwa wa malipo (pesa unayopokea) ni sawia kabisa na ukubwa wa thamani uliyotoa na ukubwa wa hatari unayobeba'. Nyuma ya hadithi ya kumpa mtoto asiye na ujuzi maalum wowote kiasi kikubwa papo hapo, 100% umefichwa mtego wa uhalifu mkali - 'kusafirisha dawa za kulevya' au kuwa 'mpokeaji wa ulaghai unaodanganya watu na kuchukua pesa zao' - unaokufanya ukamatwe na polisi mara moja na kumaliza kabisa maisha yako. Hekima ya kutahadhari kwa jicho la mantiki dhidi ya anayekaribia kwa maneno matamu na kukataa kabisa inalinda uhuru wako maisha yote." },
  { id:46, topic:"Mfumuko wa bei", emoji:"🎈",
    question:"Wakati 'kiasi cha jumla cha pesa' kinachozunguka duniani kinachapishwa kati ya nchi na benki kwa kiasi cha kupita kiasi na kuongezeka mno, kinachotokea kwa bei za jamii nzima (bei ya vitu) ni nini?",
    choices:["Kwa kuwa pesa imeongezeka sana, bei ya vitu vyote inashuka hadi sarafu 1","Kwa kuwa thamani ya uadimu ya pesa (uadimu wake) inashuka na kukaribia kipande cha karatasi, kwa uwiano 'bei ya vitu vyote inapanda ghafla kwa kasi (mfumuko wa bei)'","Hata kiasi cha pesa kibadilike, bei ya vitu haibadiliki kamwe duniani","Vitu vinaanza kubadilika kuwa umbo la noti"],
    answerIndex:1,
    explanation:"Huu ni mfumo wa 'mfumuko wa bei', ugonjwa wenye nguvu wa uchumi. Ingekuwaje kama nchi ingechapisha noti bila kikomo na kuzigawa kwa wote? Kwa kuwa wote wana pesa nyingi, sasa unatokea mvutano wa 'vitu'. Kisha unatokea mtukio wa kutisha ambapo mkate uliouzwa jana kwa sarafu 100 hauwezi kununuliwa siku inayofuata bila sarafu 10,000, na kesho kutwa bila sarafu 1,000,000. Thamani ya pesa inaporomoka, na nguvu ya pesa uliyoiweka akiba kwa shida inakuwa takataka papo hapo. Kujua usawa wa 'kiasi' cha pesa na 'idadi' ya vitu kunakupa mtazamo mpana wa dunia." },
  { id:47, topic:"Mtego wa kulipa baadaye", emoji:"💳",
    question:"Ni upi mtego mkubwa zaidi uliofichwa wa mfumo (mkopo) ambapo 'sina pesa sasa, lakini nikionyesha kadi hii (au nikitoa ahadi) naweza kununua sasa na kulipa mwezi ujao'?",
    choices:["Mwezi ujao, chombo ulichonunua kinatoweka chenyewe","Kwa kuwa pesa haipungui kutoka pochi yako sasa, hisia yako ya kiasi gani unavyozidi kuwa maskini sasa inaganda ganzi, na unaishia kubeba deni ambalo nafsi yako ya baadaye haitaweza kulilipa kamwe","Ukipoteza kadi, jina lako linabadilika kabisa","Wakati wa kununua, uzito wa mwili wako wote unaongezeka maradufu"],
    answerIndex:1,
    explanation:"Kadi za mkopo na kuandika deni (mkopo) ni vyombo rahisi sana, lakini pia mtego hatari unaopiga sehemu dhaifu ya ubongo wa binadamu. 'Noti' zinapopungua kimwili kutoka pochi, binadamu anahisi maumivu makali (hofu ya kupoteza) na anaweza kukanyaga breki, lakini kwa ahadi ya namba (kulipa baadaye) ubongo hauhisi maumivu kabisa. Hivyo unatumia kwa wepesi 'pesa ambayo nafsi yako ya baadaye inapaswa kuchuma kwa kazi ngumu'. Mwezi ujao, ukishindwa kulipa, riba inaongezwa na unafilisika papo hapo. Kuishi ndani ya mipaka ya fedha taslimu mkononi ndio msingi wa kujitegemea kiuchumi." },
  { id:48, topic:"Gharama ya fursa", emoji:"⏳",
    question:"Una 'saa 1' ya muda, au 'sarafu 1,000' za pesa. Unapochagua ufanye nini nayo, dhana ya kiuchumi usiyopaswa kuisahau kamwe, 'gharama ya fursa', inamaanisha nini?",
    choices:["Ada maalum unayopaswa kulipa nchi kila unaponunua","Kuchagua chaguo moja kunamaanisha wakati huo huo kwamba 'unaachilia na kutupa fursa au thamani nyingine nzuri ambayo ungeweza kuipata kama usingelichagua' (mbadala)","Mfumo ambapo kutumia chombo kwa muda mrefu kunaongeza thamani yake chenyewe","Inamaanisha muda unaolala nyumbani bila kufanya chochote haugharimu hata sarafu moja"],
    answerIndex:1,
    explanation:"Rasilimali zetu, kama muda na pesa, ni 'zenye kikomo kabisa (zina mipaka)' kwa kila mtu duniani. Ukinunua mchezo kwa sarafu 1,000, fursa ya kununua kitabu cha kusoma kwa sarafu 1,000 hizo inatoweka milele. Ukitumia saa 1 kuchezea, fursa ya kutumia saa hiyo kufanya kazi au kusoma inatoweka. 'Thamani nyingine kubwa zaidi unayoitolea muhanga kwa siri nyuma ya pazia kwa kuchagua kitu' inaitwa 'gharama ya fursa'. Mwenye hekima anayejua hili, anapoamua kitu, anapima 'kwa kufanya hili, ninapoteza nini badala yake?' na anaweza kuchukua chaguo lisilo baya sana." },
  { id:49, topic:"Kuchangia pamoja", emoji:"🤝",
    question:"Wakulima wa kijiji wanataka sana kutumia 'mashine kubwa ya kilimo (trekta)' iliyo ghali mno kwa mtu mmoja kuinunua, ni ipi hekima ya kiuchumi yenye busara zaidi ya kuipata kwa kuunganisha nguvu?",
    choices:["Kuomba kila siku na kusubiri mtu awe tajiri na akununulie zawadi","Wote wachangie kidogo kidogo na kuzikusanya (ushirika), wanunue mashine moja kama chombo cha pamoja cha wote, na waitumie kwa zamu kwa ratiba ya haki","Kunyemelea usiku kwenye shamba la mji mwingine na kuiba mashine kimya kimya","Kuacha kununua mashine na wote kufanya kwa mkono maisha yote"],
    answerIndex:1,
    explanation:"Hata mtaji wa mtu mmoja (pesa aliyo nayo) ukiwa mdogo, watu wengi wakikusanyika kwa lengo lile lile na kuchangia pesa kufanya bonge moja lenye nguvu, mfumo huu wa kiuchumi unaotatua tatizo kubwa unaitwa hekima ya 'ushirika' au 'fedha ndogo'. Ukitumia mashine iliyonunuliwa kwa pesa zilizokusanywa, mavuno ya shamba la wote yanaongezeka mara nyingi, na inarudi kwa wote pesa zaidi ya walizochangia. Badala ya kutegemea tajiri mwenye nguvu, wanyonge wanaamua sheria kama walio sawa, wanachangia fedha pamoja, na kuzalisha wingi kwa kujitegemea: mfumo mzuri zaidi wa eneo la kiuchumi." },
  { id:50, topic:"Muamala kati ya walio sawa", emoji:"🛒",
    question:"Unaponunua na kulipa pesa, ni upi uhusiano sahihi, kama binadamu, kati ya 'upande unaolipa (mnunuzi)' na 'upande unaouza (muuzaji)' anayepokea noti na kukabidhi bidhaa?",
    choices:["Mteja anayelipa ni mkubwa kama mungu, hivyo anaweza kumdhulumu muuzaji","Muuzaji anatoa 'bidhaa ya thamani nzuri' na mnunuzi anatoa 'pesa ya kuaminika ya thamani ile ile' - ni 'washirika walio sawa kabisa na walingana' wenye msingi wa makubaliano ya pande mbili","Duka linalouza bidhaa ni kubwa zaidi, hivyo mnunuzi sharti daima ainame na kutii","Yupi mkubwa zaidi inaamuliwa na hali ya hewa ya siku hiyo"],
    answerIndex:1,
    explanation:"Kosa baya la kawaida sana katika jamii ni dhana potofu kwamba 'upande unaolipa unaruhusiwa kujivuna'. Biashara si juu-chini ya nguvu, bali 'ubadilishanaji ulio sawa na wenye thamani sawa' wa thamani ya kila mmoja. Bila chombo rahisi alichotengeneza muuzaji kwa shida, sarafu yako ya 100 inabaki bonge la chuma tu. Kinyume chake, bila pesa yako, muuzaji hawezi kununua vitu vingine. Kila mmoja kuonyeshana heshima - 'asante kwa kuuza', 'asante kwa kununua' - ndio mafuta ya kulainisha jamii na msingi bora wa kuendeleza eneo la kiuchumi lenye upole." },
  { id:51, topic:"Kuona ndani ya matangazo", emoji:"📺",
    question:"Uliona 'tangazo' kwenye TV, mtandao, mabango, n.k., likionyesha bidhaa kuwa ya kuvutia mno. Ujihadhari na nini unapoliona?",
    choices:["Linalosemwa na tangazo ni kweli kamili 100%, hivyo unapaswa kuamini yote na kununua mara moja","Kwa kuwa lengo la tangazo ni 'kukufanya utumie pesa ili wapate faida', tilia shaka mara moja muonekano na maneno yaliyopambwa vizuri, na hesabu kwa utulivu kama lina thamani ya msingi unayohitaji kweli","Ukiona tangazo, waambie marafiki wote 'usiponunua hii utaugua'","Wote wanaotokea katika matangazo ni watu wabaya, hivyo unapaswa kukasirika daima"],
    answerIndex:1,
    explanation:"Mbinu za matangazo na masoko zimetengenezwa kuchunguza kwa kina hisia za binadamu 'naitaka!' na 'wote wanayo, mimi pia nataka kujivuna!' (sehemu dhaifu ya saikolojia), ili kukufanya ufungue pochi. Hata kibonzo cha kupendeza au mtu mashuhuri akisema 'ni bora', hiyo ni kauli tu wanayoisema baada ya kupokea pesa ya tangazo. Anayemeza taarifa ya vyombo vya habari kama ilivyo (bila uelewa wa vyombo vya habari) anachezeshwa maisha yote kwa faida ya wengine, na pochi yake inaachwa tupu. Kuwa na werevu wa kuona 'lengo lililo nyuma' ya taarifa." },
  { id:52, topic:"Jinsi bima inavyofanya kazi", emoji:"🛡️",
    question:"Tunauita nini mfumo wa kusaidiana wa pamoja duniani ambapo, dhidi ya mgogoro mkubwa wa bahati mbaya kama 'jeraha kubwa, ugonjwa mkubwa, au moto mkubwa wa nyumba' ambao hakuna anayejua lini na kwa nani utatokea, wote wanachangia kidogo kidogo kujiandaa?",
    choices:["Manunuzi","Bima (ushirika wa kusaidiana)","Ukiritimba","Akiba"],
    answerIndex:1,
    explanation:"Kama unaishi peke yako na ghafla unapata ugonjwa mkubwa unaohitaji mamilioni ya sarafu za gharama za matibabu, hauwezi kulipa na unapoteza uhai hivi hivi. Hivyo binadamu walibuni 'bima', ngao ya kiuchumi inayookoana kwa upole. Tangu wakiwa na afya, watu wengi wanachangia pesa kidogo - kama sarafu 100 kila mwezi - katika sefu kubwa moja na kuziweka akiba. Kisha mmoja wa wanachama anapopata kwa bahati mbaya jeraha kubwa, kutoka sefu hiyo inatolewa pesa kubwa kugharimia matibabu. Ni hekima nzuri zaidi ya binadamu ya kusambaza hatari: 'mmoja kwa wote, wote kwa mmoja'." },
  { id:53, topic:"Uvuvi kupita kiasi na uendelevu", emoji:"🐟",
    question:"Mvuvi, akisema 'nikivua wengi sasa naweza kupata faida kubwa', alivua kila siku kwa mpigo samaki wote wa baharini, bila kuacha hata mmoja, hadi samaki wadogo wachanga (uvuvi kupita kiasi). Kwa nini biashara hii itashindwa hakika baada ya miaka kadhaa na kuwa na njaa?",
    choices:["Kuvua samaki wengi mno kunamkasirisha mungu wa bahari na kubadilisha noti zote kuwa mchanga","Rasilimali za asili (mimea na wanyama) zina 'kasi ya kuzaliana' ya kuzaa watoto na kuongezeka, na ukiizidi na kuwaangamiza, utakachouza baadaye kinatoweka kabisa (kuporomoka kwa uendelevu)","Kuvua samaki wengi mno kunawafanya wazito mno hata mashua inaelea angani","Idadi ya samaki ikishuka, joto la maji ya bahari linapanda hadi nyuzi 100 na linakuwa hatari"],
    answerIndex:1,
    explanation:"Dhana isiyoweza kupuuzwa kamwe ili uchumi udumu milele ni 'uendelevu'. Baraka za asili za Dunia si chemchemi ibubujikayo bila kikomo. Kanuni kubwa ni kutumia samaki na miti ya msitu ndani ya mipaka ya kasi wanavyoongezeka kiasili, kama kupokea kidogo 'riba'. Mfanyabiashara mpumbavu anayefikiria faida ya papo hapo tu anaharibu kwa mikono yake asili, msingi, na baada ya miaka kadhaa anawafanya wote wawe na njaa na kujiangamiza. Kuwa na mtazamo mpana wa kuishi kwa busara huku ukiacha rasilimali kwa watoto wa baadaye." },
  { id:54, topic:"Ujuzi adimu", emoji:"🧠",
    question:"Mtu anayepokea 'mshahara (malipo)' mwingi kwa kazi yake katika jamii si mtu mwenye mwili mkubwa tu au anayejivuna, bali mtu wa sifa gani?",
    choices:["Mtu anayepiga kelele zaidi ya wote kila siku akiomba pesa","Mtu mwenye 'maarifa maalum, ujuzi wa juu, uzoefu wa kina' ambao hakuna mwingine anaweza kuiga kwa urahisi, na anayeweza kutatua matatizo makubwa ya jamii (kipaji adimu)","Mtu aliye bora zaidi duniani kwa kuzubaa katika saa za kazi","Mtu asiyetoka nje ya nyumba kila siku na analala tu kimya"],
    answerIndex:1,
    explanation:"Kanuni inayoamua kiasi cha mshahara nayo kwa kweli inasonga kulingana na sheria ya 'mahitaji na ugavi'. Kazi rahisi ambayo yeyote anaweza kuiga kwa sekunde 1 ina maelfu kwa maelfu ya watu duniani wanaoweza kuifanya badala yako, hivyo mshahara ni mdogo. Lakini mtu mwenye 'maarifa ya kitaalamu (ujuzi)' aliyopata kwa miaka mingi ya kusoma na juhudi - kama 'naweza kufanya upasuaji na kuponya ugonjwa huu mgumu' au 'naweza kutengeneza mfumo rahisi ambao hakuna anaweza' - anakuwa 'kipaji adimu chenye thamani kubwa' bila mbadala duniani. Ukitaka kupokea pesa nyingi, jibu sahihi si kupiga kelele, bali kunoa kichwa na ujuzi wako na kuwa kiumbe wa pekee anayetafutwa na jamii." },
  { id:55, topic:"Faida ya ushindani", emoji:"🏁",
    question:"Katika barabara ile ile yalitokea maduka mawili yanayouza nyama, 'Duka A' na 'Duka B' (ushindani). Maduka haya mawili kushindana yanaleta faida gani nzuri kwa wanunuzi (raia)?",
    choices:["Kwa maduka mawili, ladha ya nyama inabadilika yenyewe kuwa ladha ya chokoleti","Ili mnunuzi achague duka lao, kila moja linaanza kujitahidi kwa nguvu 'tufanye bei iwe rahisi zaidi' na 'tufanye nyama iwe mbichi na tamu zaidi'","Maduka mawili yanapigana ngumi vikali kila siku na unaweza kutazama","Kununua nyama daima kunachukua muda mara mbili"],
    answerIndex:1,
    explanation:"Washindani wanaouza bidhaa ile ile sokoni kushindana kunaitwa 'ushindani'. Kwa ushindani, wenye maduka hawawezi kuzubaa. Kama Duka A lingeuza nyama mbaya kwa bei kubwa, wateja wote wangeenda Duka B, na Duka A lingefilisika. Ndio maana kila moja linatumia kichwa kwa nguvu na kurudia jitihada za 'jinsi ya kuwafikishia wote vitu vya bei rahisi na bora zaidi'. Nishati hii ya ushindani ni injini inayofanya teknolojia, tiba, na ubora wa huduma za jamii nzima viendelee kuboreka zaidi na zaidi kila siku." },
  { id:56, topic:"Kuongeza uzalishaji", emoji:"🚜",
    question:"Tunauita nini, kwa lugha ya uchumi, maendeleo makubwa zaidi ya kuingiza 'vyombo vya chuma na matrekta (mashine)' vilivyotengenezwa kwa hekima, kutoka maisha ya kulima shamba kwa mkono?",
    choices:["Upanuzi wa matumizi","Kuongezeka kwa uzalishaji","Kufufuka kwa kubadilishana bidhaa","Kukamilika kwa ukiritimba"],
    answerIndex:1,
    explanation:"Hata kwa muda ule ule na nguvu ile ile ya kazi ya binadamu, kuongeza kiasi cha matokeo unayoweza kuzalisha mara nyingi au mara kumi kwa kutumia vyombo, mashine, na mifumo bora kunaitwa 'kuongezeka kwa uzalishaji'. Mtu aliyekuwa akichukua siku nzima kwa mkono kuchimba kiazi kimoja anaweza, kwa trekta, kuvuna viazi 100 kwa saa moja. Uzalishaji ukipanda, chakula na utajiri vinafurika kwa wingi katika jamii, na hata bila wote kufanya kazi saa nyingi wakitoka jasho kama watumwa, unaweza kuumbwa muda huru (mapumziko) ambapo wote wanaishi kwa usalama, kwa utulivu, na kwa wingi. Hekima inarahisisha kazi." },
  { id:57, topic:"Biashara na usambazaji", emoji:"🚢",
    question:"Ni nini maana nzuri ya mfumo wa 'biashara' au usambazaji, ambapo unabadilisha chumvi au dawa adimu isiyopatikana kamwe katika eneo lako, kwa nguo walizo nazo watu wa eneo la mbali tofauti?",
    choices:["Kwenda mbali kunachanganya majina ya nchi za kila mmoja na kuyafanya yatoweke","Kwa kubadilisha vilivyotengenezwa kwa kutumia 'nguvu za rasilimali na hali ya hewa ambazo kila ardhi ya Dunia inazimudu', wote wanaweza kufurahia kwa usawa utajiri ambao eneo moja peke yake lisingeupata kamwe","Kufanya biashara kunapunguza ukubwa wa Dunia nusu","Sheria kwamba kununua vitu vya mbali daima kunafanya ukungu uote kwenye noti"],
    answerIndex:1,
    explanation:"Duniani daima kuna kutokuwa na usawa wa rasilimali kulingana na eneo: maeneo ya baridi, maeneo ya joto, maeneo yenye milima mingi, maeneo karibu na bahari. Ukijifungia katika kijiji kimoja ukiishi kwa kujitegemea, watu wa maeneo yasiyopatikana chumvi wanaugua na kufa. Binadamu waliendeleza hekima ya 'usambazaji na biashara', kuunganisha na kubadilishana na maeneo ya mbali bidhaa maalum zilizotengenezwa kwa kutumia nguvu ya kila ardhi. Kwa hii imeundwa mtandao wa kusaidiana wa kiwango cha dunia, ambapo binadamu wote wa dunia wanagawana baraka za Dunia nzima na wanaweza kupata utajiri kwa usalama popote walipo." },
  { id:58, topic:"Kutolingana kwa taarifa", emoji:"🔍",
    question:"Unapokwenda kununua chombo, kwa nini hupaswi kununua mara moja kwa bei uliyoiona dukani la kwanza tu, bali kuzunguka maduka mengine kadhaa na soko kuona bei zao (kukusanya taarifa)?",
    choices:["Kutembea sana kunaimarisha msuguano wa nyayo za viatu vyako na kukufanya ukimbie haraka zaidi","Kama kuna 'pengo la taarifa (hali ambayo upande mmoja tu unajua ukweli)' kati ya muuzaji na mnunuzi, kuna hatari ya kufanywa ununue kwa bei kubwa isiyo ya haki (uchukuzi) juu ya bei ya soko na kupata hasara kubwa","Kuzunguka maduka mengi kunabadilisha rangi ya noti kuwa dhahabu nzuri","Sheria kwamba kununua dukani moja kunamhuzunisha mtu wa duka"],
    answerIndex:1,
    explanation:"Katika biashara daima kuna watu wabaya ambao, wakitumia ukweli kwamba mnunuzi hajui thamani halisi au bei ya soko (bei ya wastani) ya bidhaa, wanapandisha bei mara 10 ya kawaida na kujaribu kulaghai. Kwa lugha ya uchumi hii inaitwa 'kutolingana kwa taarifa'. Ili usiingie mtego huu, kabla ya kufungua pochi, kukusanya mwenyewe 'data za taarifa' kwa kufungua vitabu au kuzunguka maduka kadhaa ndio kizuizi chenye nguvu zaidi. Asiye na maarifa pesa yake inanyang'anywa, na mwenye taarifa sahihi anaweza kujilinda: huu ndio ukweli mgumu wa jamii." },
  { id:59, topic:"Mchango na kutoa", emoji:"🎁",
    question:"Bila kutaka malipo yoyote, kitendo cha kushiriki pesa au chakula chako na mtu asiye na pesa kweli aliye taabani, au mtu aliyejeruhiwa asiyeweza kufanya kazi (mchango au kutoa), ni ipi hekima yake ya kweli katika jamii?",
    choices:["Kutupa pesa tu mfereji na kujifanya maskini kwa makusudi kwa burudani","Kwa kuondoa katika jamii 'watu ambao katika kukata tamaa hawana ila kugeukia uhalifu' au 'watu wanaokufa njaa', na kuinua usalama (utulivu) na upole wa mji mzima, unaweza kulinda, kwa kurudi, kwa uhakika zaidi uhai wako mwenyewe na usalama wako wa baadaye","Kumpa mtu mwingine pesa kunafanya pesa mpya iangukie kutoka angani siku inayofuata","Kujivuna mbele ya mtu aliye taabani na kujihisi umekuwa mungu mkubwa"],
    answerIndex:1,
    explanation:"Asili ya kweli ya 'mchango au kutoa' bila malipo si kujitolea kwa kujitoa muhanga tu. Ni uwekezaji katika 'wavu wa usalama wa kijamii (mstari wa ulinzi)' wenye busara zaidi, kuzuia kuporomoka kwa kutisha kwa utulivu ambapo chini ya jamii inabomoka na watu maskini hawawezi kuishi bila kutenda uhalifu. Pesa ya upole uliyoitumia leo kuokoa maumivu ya mwingine inakurudia, kwa kurudi, kama thamani kubwa zaidi ya mji salama ambapo kesho wewe mwenyewe hushambuliwi na wezi. Kuzungusha upole ni hekima kubwa zaidi ya kijamii ya binadamu ya kunusurika bila kujiangamiza." },
  { id:60, topic:"Kuwa bwana wa pesa", emoji:"🧭",
    question:"Ukishajifunza katika Pakiti ya 2 ya programu hii 'Wise World 3' kuhusu mfumo wa uaminifu ulio nyuma ya uchumi mwingi na noti, ni lipi lengo la mwisho la kweli katika maisha yako mwenyewe?",
    choices:["Kulundika pesa nyingi zaidi duniani na kuwa mfalme anayeamuru wengine na kuwatawala kwa pesa","Si kuwa mtumwa wa pesa, chombo cha namba, bali kuona kwa usahihi 'mfumo wa uaminifu na shukrani' ulio nyuma ya noti, kutumia hekima yako kutawala pesa kwa upole, na kuimudu kulinda haki za binadamu na furaha yako na ya walio karibu nawe","Kununua hadi kikomo kila siku na kujaza nyumba takataka, mwisho","Kupata kombe kwa kujibu yote kwa usahihi na kuacha kabisa kusoma"],
    answerIndex:1,
    explanation:"Hongera! Kwa hii maswali 30 ya Pakiti ya 2 yote yamekamilika. Pesa, ukiitumia hatua moja vibaya, inabadilika kuwa mnyororo wa kutisha wa shetani unaowafanya watu watilie shaka, unaowafanya wasaliti, na kunyang'anya uhuru wa watu maisha yote. Lakini ukiwa na 'dira ya hekima ya kiuchumi' uliyojifunza katika maswali haya, hutadanganywa tena na namba za noti. Pesa si zaidi ya chombo rahisi kinachofanya 'nishati ya uaminifu' - inayozaliwa unapotatua tatizo la mtu - rahisi kubeba. Badala ya kutawaliwa na pesa, tumia hekima yako kuwa 'bwana anayeidhibiti kwa upole'. Na, kwa usawa na haki na wenzako duniani kote, shirikiana kujenga kwa mikono yako dunia yenye upole ambapo hakuna anayekufa njaa. Dunia nzima inashangilia kujitegemea kwako kwa busara!" }
];
